import React, { useState, useMemo } from "react";
import "./BatchDashboard.css";

function BatchDashboard({ dashboardData }) {
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(50);
  const [searchTerm, setSearchTerm] = useState("");
  const [activeTab, setActiveTab] = useState("predictions");
  const [downloadLoading, setDownloadLoading] = useState(false);

  if (!dashboardData || !dashboardData.batchResult) {
    return (
      <div className="batch-dashboard">
        <div className="no-data-message">
          <h3>No Batch Analysis Results Available</h3>
          <p>Please run a batch analysis first from the Batch Processing section.</p>
        </div>
      </div>
    );
  }

  const { batchResult } = dashboardData;
  const { 
    dataset_info, 
    risk_analysis, 
    customer_segmentation, 
    feature_analysis, 
    all_predictions, 
    data_source,
    processing_pipeline,
    eda_results,
    dataset_id
  } = batchResult;

  // Calculate percentages for risk distribution
  const totalCustomers = dataset_info.total_customers;
  const riskDistribution = risk_analysis.risk_distribution || {};

  // Calculate risk counts from distribution
  const lowRiskCount = riskDistribution['P3: Low Risk (<=30%)'] || 0;
  const mediumRiskCount = riskDistribution['P2: Moderate Risk (31-70%)'] || 0;
  const highRiskCount = riskDistribution['P1: High Risk (>70%)'] || 0;

  // Filter and paginate ALL predictions
  const filteredPredictions = useMemo(() => {
    if (!all_predictions) return [];
    
    return all_predictions.filter(customer => {
      if (!searchTerm) return true;
      
      const searchLower = searchTerm.toLowerCase();
      return (
        (customer.Customer_ID && customer.Customer_ID.toString().toLowerCase().includes(searchLower)) ||
        (customer.Risk_Level && customer.Risk_Level.toLowerCase().includes(searchLower)) ||
        (customer.Predicted_Churn && customer.Predicted_Churn.toString().toLowerCase().includes(searchLower))
      );
    });
  }, [all_predictions, searchTerm]);

  // Pagination calculations
  const totalPages = Math.ceil(filteredPredictions.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentPredictions = filteredPredictions.slice(startIndex, endIndex);

  // Function to download processed dataset with EDA
  const downloadProcessedData = async () => {
    try {
      setDownloadLoading(true);
      
      const response = await fetch('http://localhost:5000/api/batch/download-processed-data', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          dataset_id: dataset_id
        }),
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      a.download = `processed_dataset_with_eda_${new Date().toISOString().slice(0,19)}.csv`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      setDownloadLoading(false);
    } catch (error) {
      console.error('Error downloading processed data:', error);
      alert('Error downloading processed data: ' + error.message);
      setDownloadLoading(false);
    }
  };

  // Function to download predictions with processing info
  const downloadPredictions = async () => {
    try {
      setDownloadLoading(true);
      
      // Get the original file
      let fileToProcess = null;
      const fileInput = document.getElementById('batch-file');
      if (fileInput && fileInput.files && fileInput.files[0]) {
        fileToProcess = fileInput.files[0];
      } else if (window.uploadedBatchFile) {
        fileToProcess = window.uploadedBatchFile;
      } else {
        alert("❌ No CSV file found. Please upload your CSV file again.");
        setDownloadLoading(false);
        return;
      }

      const formData = new FormData();
      formData.append('file', fileToProcess);

      const response = await fetch('http://localhost:5000/api/batch/download-predictions', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      a.download = `churn_predictions_with_processing_${new Date().toISOString().slice(0,19)}.csv`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      setDownloadLoading(false);
    } catch (error) {
      console.error('Error downloading predictions:', error);
      alert('Error downloading predictions: ' + error.message);
      setDownloadLoading(false);
    }
  };

  // Function to handle page change
  const handlePageChange = (newPage) => {
    setCurrentPage(newPage);
  };

  // Function to handle items per page change
  const handleItemsPerPageChange = (e) => {
    setItemsPerPage(Number(e.target.value));
    setCurrentPage(1);
  };

  return (
    <div className="batch-dashboard">
      <div className="dashboard-header">
        <h2>📊 Complete Analysis Dashboard</h2>
        <div className="header-actions">
          <button 
            className="download-report-btn"
            onClick={downloadProcessedData}
            disabled={downloadLoading}
          >
            {downloadLoading ? '⏳ Downloading...' : '📥 Download Processed Data'}
          </button>
        </div>
      </div>

      {/* Processing Pipeline Status */}
      {processing_pipeline && (
        <div className="section-card processing-pipeline">
          <h3>⚙️ Data Processing Pipeline</h3>
          <div className="pipeline-status">
            <div className={`status-badge ${processing_pipeline.status}`}>
              {processing_pipeline.status.toUpperCase()}
            </div>
            <div className="pipeline-stats">
              <span>Steps: {processing_pipeline.steps}</span>
              <span>Ready for ML: {processing_pipeline.final_quality.dataset_ready_for_ml ? '✅' : '❌'}</span>
            </div>
          </div>
          
          {eda_results && (
            <div className="eda-summary">
              <h4>📈 EDA Summary</h4>
              <div className="eda-grid">
                <div className="eda-stat">
                  <div className="eda-value">{eda_results.final_quality.original_shape[0]}</div>
                  <div className="eda-label">Original Rows</div>
                </div>
                <div className="eda-stat">
                  <div className="eda-value">{eda_results.final_quality.final_shape[0]}</div>
                  <div className="eda-label">Processed Rows</div>
                </div>
                <div className="eda-stat">
                  <div className="eda-value">{eda_results.missing_values.total_missing}</div>
                  <div className="eda-label">Missing Values Handled</div>
                </div>
                <div className="eda-stat">
                  <div className="eda-value">{eda_results.final_quality.columns_added.length}</div>
                  <div className="eda-label">New Features</div>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Dataset Overview */}
      <div className="section-card dataset-overview">
        <h3>📁 Dataset Overview</h3>
        <div className="dataset-stats-grid">
          <div className="stat-card">
            <div className="stat-value">{dataset_info.total_customers}</div>
            <div className="stat-label">Total Customers</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{dataset_info.total_features}</div>
            <div className="stat-label">Features Analyzed</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{dataset_info.dataset_size_kb.toFixed(1)} KB</div>
            <div className="stat-label">Dataset Size</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{risk_analysis.total_predicted_churn}</div>
            <div className="stat-label">Predicted Churn</div>
          </div>
        </div>
        
        <div className="data-source-info">
          <span className="source-label">Data Source:</span>
          <span className="source-value">{data_source === "demo" ? "Demo Data" : "Uploaded CSV"}</span>
          {dataset_id && (
            <>
              <span className="source-label">Dataset ID:</span>
              <span className="source-value">{dataset_id}</span>
            </>
          )}
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="section-card tabs-navigation">
        <div className="tabs">
          <button 
            className={`tab ${activeTab === 'predictions' ? 'active' : ''}`}
            onClick={() => setActiveTab('predictions')}
          >
            👥 Customer Predictions
          </button>
          <button 
            className={`tab ${activeTab === 'processing' ? 'active' : ''}`}
            onClick={() => setActiveTab('processing')}
          >
            ⚙️ Processing Details
          </button>
          <button 
            className={`tab ${activeTab === 'analysis' ? 'active' : ''}`}
            onClick={() => setActiveTab('analysis')}
          >
            📊 Risk Analysis
          </button>
        </div>
      </div>

      {/* Processing Details Tab */}
      {activeTab === 'processing' && eda_results && (
        <div className="section-card processing-details">
          <h3>🔍 Data Processing Details</h3>
          
          <div className="processing-section">
            <h4>📋 Processing Steps</h4>
            <div className="steps-list">
              {eda_results.processing_steps.map((step, index) => (
                <div key={index} className="processing-step">
                  <span className="step-number">{index + 1}.</span>
                  <span className="step-text">{step}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="processing-section">
            <h4>🧹 Data Quality</h4>
            <div className="quality-grid">
              <div className="quality-item">
                <span className="quality-label">Missing Values Handled:</span>
                <span className="quality-value">{eda_results.missing_values.total_missing}</span>
              </div>
              <div className="quality-item">
                <span className="quality-label">Zero Values Identified:</span>
                <span className="quality-value">{eda_results.data_quality.zero_values.total_zeros}</span>
              </div>
              <div className="quality-item">
                <span className="quality-label">Remaining Missing:</span>
                <span className="quality-value">{eda_results.final_quality.remaining_missing}</span>
              </div>
              <div className="quality-item">
                <span className="quality-label">Dataset Ready for ML:</span>
                <span className="quality-value">{eda_results.final_quality.dataset_ready_for_ml ? '✅ Yes' : '❌ No'}</span>
              </div>
            </div>
          </div>

          {eda_results.correlation_analysis && eda_results.correlation_analysis.top_correlations.length > 0 && (
            <div className="processing-section">
              <h4>📈 Top Correlations</h4>
              <div className="correlations-list">
                {eda_results.correlation_analysis.top_correlations.slice(0, 5).map((corr, index) => (
                  <div key={index} className="correlation-item">
                    <span className="correlation-pair">{corr.feature1} ↔ {corr.feature2}</span>
                    <span className={`correlation-value ${corr.strength}`}>
                      {corr.correlation.toFixed(3)} ({corr.strength})
                    </span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Risk Analysis Tab */}
      {activeTab === 'analysis' && (
        <div className="section-card risk-analysis">
          <h3>⚠️ Risk Analysis Summary</h3>
          <div className="risk-metrics-grid">
            <div className="risk-metric">
              <div className="metric-value">{risk_analysis.average_probability?.toFixed(3) || '0.000'}</div>
              <div className="metric-label">Average Churn Probability</div>
            </div>
            <div className="risk-metric">
              <div className="metric-value">{((risk_analysis.churn_rate || 0) * 100).toFixed(1)}%</div>
              <div className="metric-label">Overall Churn Rate</div>
            </div>
            <div className="risk-metric">
              <div className="metric-value">{customer_segmentation.high_risk_customers || 0}</div>
              <div className="metric-label">High-Risk Customers</div>
            </div>
            <div className="risk-metric">
              <div className="metric-value">₹{(customer_segmentation.potential_revenue_loss || 0).toLocaleString()}</div>
              <div className="metric-label">Potential Revenue Loss</div>
            </div>
          </div>

          {/* Risk Distribution */}
          <div className="risk-distribution">
            <h4>Risk Level Distribution</h4>
            <div className="distribution-bars">
              {Object.entries(riskDistribution).map(([riskLevel, count]) => {
                const percentage = totalCustomers > 0 ? (count / totalCustomers * 100).toFixed(1) : 0;
                let barColor = "";
                
                if (riskLevel.includes("High")) barColor = "high-risk";
                else if (riskLevel.includes("Moderate")) barColor = "medium-risk";
                else barColor = "low-risk";

                return (
                  <div key={riskLevel} className="distribution-item">
                    <div className="risk-label">{riskLevel}</div>
                    <div className="bar-container">
                      <div 
                        className={`risk-bar ${barColor}`}
                        style={{ width: `${percentage}%` }}
                      >
                        <span className="bar-count">{count} customers</span>
                      </div>
                    </div>
                    <div className="risk-percentage">{percentage}%</div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}

      {/* Predictions Tab */}
      {activeTab === 'predictions' && (
        <div className="section-card all-predictions">
          <div className="predictions-header">
            <h3>👥 All Customer Predictions ({totalCustomers} Total)</h3>
            <div className="predictions-controls">
              <div className="search-box">
                <input
                  type="text"
                  placeholder="Search customers..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="search-input"
                />
              </div>
              <div className="pagination-controls">
                <select 
                  value={itemsPerPage} 
                  onChange={handleItemsPerPageChange}
                  className="items-per-page-select"
                >
                  <option value={20}>20 per page</option>
                  <option value={50}>50 per page</option>
                  <option value={100}>100 per page</option>
                  <option value={200}>200 per page</option>
                </select>
                
                <div className="pagination-info">
                  Showing {startIndex + 1}-{Math.min(endIndex, filteredPredictions.length)} of {filteredPredictions.length} customers
                </div>
                
                <div className="pagination-buttons">
                  <button
                    onClick={() => handlePageChange(currentPage - 1)}
                    disabled={currentPage === 1}
                    className="pagination-btn"
                  >
                    Previous
                  </button>
                  <span className="page-info">
                    Page {currentPage} of {totalPages}
                  </span>
                  <button
                    onClick={() => handlePageChange(currentPage + 1)}
                    disabled={currentPage === totalPages}
                    className="pagination-btn"
                  >
                    Next
                  </button>
                </div>
              </div>
            </div>
          </div>

          <div className="predictions-table-container">
            <div className="predictions-table">
              <table>
                <thead>
                  <tr>
                    <th>Customer ID</th>
                    <th>Churn Probability</th>
                    <th>Risk Level</th>
                    <th>Prediction</th>
                    <th>Tenure</th>
                    <th>Order Count</th>
                    <th>Cashback</th>
                    <th>Days Since Last Order</th>
                    <th>Satisfaction</th>
                  </tr>
                </thead>
                <tbody>
                  {currentPredictions.map((customer, index) => {
                    const riskLevel = customer.Risk_Level || 'Unknown';
                    const churnProbability = customer.Churn_Probability || 0;
                    
                    return (
                      <tr key={index}>
                        <td className="customer-id">
                          {customer.Customer_ID || customer.CustomerID || `CUST_${startIndex + index + 1}`}
                        </td>
                        <td>
                          <div className="probability-bar">
                            <div 
                              className="probability-fill"
                              style={{ width: `${churnProbability * 100}%` }}
                            ></div>
                            <span className="probability-text">
                              {(churnProbability * 100).toFixed(1)}%
                            </span>
                          </div>
                        </td>
                        <td>
                          <span className={`risk-badge ${riskLevel.toLowerCase().replace(' ', '-')}`}>
                            {riskLevel}
                          </span>
                        </td>
                        <td>
                          <span className={`prediction ${customer.Predicted_Churn ? 'churn' : 'no-churn'}`}>
                            {customer.Predicted_Churn ? "🚨 Churn" : "✅ Retain"}
                          </span>
                        </td>
                        <td>{customer.Tenure || 'N/A'}</td>
                        <td>{customer.OrderCount || 'N/A'}</td>
                        <td>₹{(customer.CashbackAmount || 0).toLocaleString()}</td>
                        <td>{customer.DaySinceLastOrder || 'N/A'}</td>
                        <td>
                          <div className="satisfaction-score">
                            {customer.SatisfactionScore || 'N/A'}
                            {customer.SatisfactionScore && (
                              <span className="score-stars">
                                {'★'.repeat(customer.SatisfactionScore)}{'☆'.repeat(5 - customer.SatisfactionScore)}
                              </span>
                            )}
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>

          {filteredPredictions.length === 0 && (
            <div className="no-results">
              <p>No customers found matching your search criteria.</p>
            </div>
          )}
        </div>
      )}

      {/* Download Section */}
      <div className="section-card download-section">
        <h3>📥 Download Reports</h3>
        <div className="download-options">
          <div className="download-option">
            <h4>📊 Processed Dataset with EDA</h4>
            <p>Download the complete processed dataset with comprehensive EDA report, including all data cleaning steps, missing value handling, and feature engineering details.</p>
            <button 
              className="download-btn primary" 
              onClick={downloadProcessedData}
              disabled={downloadLoading}
            >
              {downloadLoading ? '⏳ Downloading...' : '📥 Download Processed Data & EDA Report'}
            </button>
          </div>
          
          <div className="download-option">
            <h4>🤖 Predictions with Processing Info</h4>
            <p>Download churn predictions with complete processing information, including risk levels, probabilities, and all original features.</p>
            <button 
              className="download-btn secondary" 
              onClick={downloadPredictions}
              disabled={downloadLoading}
            >
              {downloadLoading ? '⏳ Downloading...' : '📊 Download Predictions Report'}
            </button>
          </div>
        </div>
        
        <div className="report-features">
          <h5>All Reports Include:</h5>
          <ul>
            <li>✅ Complete data processing history</li>
            <li>✅ EDA summary and quality metrics</li>
            <li>✅ Missing value handling details</li>
            <li>✅ Feature engineering steps</li>
            <li>✅ Churn probabilities and risk levels</li>
            <li>✅ Original and processed features</li>
            <li>✅ Business metrics and insights</li>
          </ul>
        </div>
      </div>

      {/* Hidden file input for re-upload */}
      <input
        type="file"
        accept=".csv"
        id="batch-file"
        style={{ display: 'none' }}
        onChange={() => {}}
      />
    </div>
  );
}

export default BatchDashboard;
